// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };

// Form state for all 4 steps
export default function Component(props: Props) {
  // Form state for all 4 steps
  const [currentStep, setCurrentStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  // Validation state
  const [nameError, setNameError] = useState('');
  const [emailError, setEmailError] = useState('');

  // Validation helpers
  const validateEmail = useCallback((value: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(value);
  }, []);

  const validateName = useCallback((value: string): boolean => {
    return value.trim().length > 0;
  }, []);

  const isStep1Valid = useMemo(() => {
    return validateName(name) && validateEmail(email);
  }, [name, email, validateName, validateEmail]);

  const isStep2Valid = useMemo(() => {
    return satisfaction !== '';
  }, [satisfaction]);

  const isStep3Valid = useMemo(() => {
    return true; // Step 3 (features) is optional
  }, []);

  // Handle name change with validation
  const handleNameChange = useCallback((value: string) => {
    setName(value);
    if (value.trim().length === 0) {
      setNameError('Name is required');
    } else {
      setNameError('');
    }
  }, []);

  // Handle email change with validation
  const handleEmailChange = useCallback((value: string) => {
    setEmail(value);
    if (value.trim().length === 0) {
      setEmailError('Email is required');
    } else if (!validateEmail(value)) {
      setEmailError('Please enter a valid email address');
    } else {
      setEmailError('');
    }
  }, [validateEmail]);

  // Handle feature toggle
  const handleFeatureToggle = useCallback((feature: string) => {
    setFeatures((prev) =>
      prev.includes(feature) ? prev.filter((f) => f !== feature) : [...prev, feature]
    );
  }, []);

  // Handle next step
  const handleNext = useCallback(() => {
    if (currentStep === 1 && !isStep1Valid) return;
    if (currentStep === 2 && !isStep2Valid) return;
    if (currentStep === 3) return; // Step 3 is optional, always allow next
    if (currentStep < 5) {
      setCurrentStep((prev) => prev + 1);
    }
  }, [currentStep, isStep1Valid, isStep2Valid, isStep3Valid]);

  // Handle back step
  const handleBack = useCallback(() => {
    if (currentStep > 1) {
      setCurrentStep((prev) => prev - 1);
    }
  }, [currentStep]);

  // Handle submit on final step
  const submit = useAction<ActionSubmitPayload>('submit');
  const handleSubmit = useCallback(() => {
    const satisfactionNumber = parseInt(satisfaction, 10);
    submit({
      name: name.trim(),
      email: email.trim(),
      satisfaction: satisfactionNumber,
      features,
      comments: comments.trim(),
    });
  }, [name, email, satisfaction, features, comments, submit]);

  // Satisfaction radio options from props
  const satisfactionOptions = useMemo(() => {
  const satisfactionOptions = useMemo(() => {
    return (props.satisfactionLabels?.map((label, index) => ({
      value: String(index + 1),
      label,
    })) || []);
  }, [props.satisfactionLabels]);

  // Feature checkbox options from props
  const featureCheckboxOptions = useMemo(() => {
    return (props.featureOptions?.map((feature) => ({
      value: feature,
      label: feature,
    })) || []);
  }, [props.featureOptions]);


  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={24}>
        {/* PROGRESS BAR */}
        <Stack gap={8}>
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">{`Step ${currentStep} of 5`}</Text>
          <Progress value={currentStep} max={5} size="sm" />
        </Stack>

        {/* HEADER */}
        <Stack gap={8}>
          <Heading level={2}>Survey Form</Heading>
        </Stack>

        {/* CONTENT - STEP 1: Name and Email */}
        {currentStep === 1 && (
          <Card padding={24} shadow="md">
            <Stack gap={16}>
              <Text variant="label" weight="semibold">Personal Information</Text>
              <Input
                label="Name"
                placeholder="John Doe"
                value={name}
                onChange={handleNameChange}
                error={nameError}
                required
              />
              <Input
                label="Email"
                type="email"
                placeholder="john@example.com"
                value={email}
                onChange={handleEmailChange}
                error={emailError}
                required
              />
            </Stack>
          </Card>
        )}

        {/* CONTENT - STEP 2: Satisfaction Rating */}
        {currentStep === 2 && (
          <Card padding={24} shadow="md">
            <Stack gap={16}>
              <Text variant="label" weight="semibold">How satisfied are you?</Text>
              <RadioGroup
                label="Satisfaction Rating"
                value={satisfaction}
                onChange={setSatisfaction}
                options={satisfactionOptions}
                direction="horizontal"
              />
            </Stack>
          </Card>
        )}

        {/* CONTENT - STEP 3: Feature Interests */}
        {currentStep === 3 && (
          <Card padding={24} shadow="md">
           <Card padding={24} shadow="md">
             <Stack gap={16}>
               <Text variant="label" weight="semibold">Which features interest you?</Text>
               {props.featureOptions && props.featureOptions.map((feature) => (
                 <Checkbox
                   key={feature}
                   label={feature}
                   checked={features.includes(feature)}
                   onChange={() => handleFeatureToggle(feature)}
                 />
               ))}
             </Stack>
           </Card>

        {/* CONTENT - STEP 4: Comments */}
        {currentStep === 4 && (
          <Card padding={24} shadow="md">
            <Stack gap={16}>
              <Text variant="label" weight="semibold">Additional Comments</Text>
              <TextArea
                label="Comments"
                placeholder="Please share any additional feedback..."
                value={comments}
                onChange={setComments}
                rows={6}
                maxLength={500}
                showCount
              />
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="right">{comments.length}/500</Text>
            </Stack>
          </Card>
        )}

        {/* CONTENT - STEP 5: Review */}
        {currentStep === 5 && (
          <Card padding={24} shadow="md">
            <Stack gap={16}>
              <Text variant="label" weight="semibold">Review Your Answers</Text>
              <Divider />
              <Stack gap={12}>
                <Stack gap={4}>
                  <Text variant="label">Name</Text>
                  <Text variant="body">{name}</Text>
                </Stack>
                <Stack gap={4}>
                  <Text variant="label">Email</Text>
                  <Text variant="body">{email}</Text>
                </Stack>
                <Stack gap={4}>
                  <Text variant="label">Satisfaction</Text>
                  <Text variant="body">{satisfaction && props.satisfactionLabels && props.satisfactionLabels.length > 0 ? props.satisfactionLabels[Math.max(0, Math.min(parseInt(satisfaction, 10) - 1, props.satisfactionLabels.length - 1))] : 'N/A'}</Text>
                </Stack>
                <Stack gap={4}>
                  <Text variant="label">Features</Text>
                  <Stack direction="horizontal" gap={8} wrap>
                    {features.map((feature) => (
                      <Badge key={feature} variant="primary" size="sm">{feature}</Badge>
                    ))}
                  </Stack>
                </Stack>
                <Stack gap={4}>
                  <Text variant="label">Comments</Text>
                  <Text variant="body">{comments || '(No comments)'}</Text>
                </Stack>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* FOOTER / ACTIONS */}
        <Row gap={8} justify="between">
          <Button
            variant="ghost"
            onClick={handleBack}
            disabled={currentStep === 1}
          >
            Back
          </Button>
          {currentStep < 5 && (
            <Button
              variant="primary"
              onClick={handleNext}
              disabled={
                (currentStep === 1 && !isStep1Valid) ||
                (currentStep === 2 && !isStep2Valid) ||
                (currentStep === 3 && false)
              }
            >
              Next
            </Button>
          )}
          {currentStep === 5 && (
            <Button variant="primary" onClick={handleSubmit}>
              Submit
            </Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column?: string; title?: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




export default function Component(props: Props) {
  // State management
  const [tasks, setTasks] = useState(props.tasks || []);
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState('');
  const [addingColumnId, setAddingColumnId] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  // Actions — fire-and-forget to agent
  const taskUpdateAction = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  // Sync external task updates from stream
  useEffect(() => {
    const event = taskChanged?.latest;
    if (!event?.task?.id) return;
    const updated = event.task;
    setTasks((prev) => {
      if (event.action === 'delete') {
        return prev.filter((t) => t.id !== updated.id);
      }
      const idx = prev.findIndex((t) => t.id === updated.id);
      if (idx >= 0) {
        const newTasks = [...prev];
        if (editingTaskId === updated.id) {
          newTasks[idx] = { ...newTasks[idx], ...updated, title: editingTitle };
        } else {
          newTasks[idx] = { ...newTasks[idx], ...updated };
        }
        return newTasks;
      }
      if (event.action === 'create') {
        return [...prev, updated];
      }
      return prev;
    });
  }, [taskChanged, editingTaskId, editingTitle]);

  // Computed values
  const tasksByColumn = useMemo(() => {
    const grouped: Record<string, typeof tasks> = {};
    props.columns.forEach((col) => {
      if (col.id) grouped[col.id] = [];
    });
    tasks.forEach((task) => {
      if (task.column && grouped[task.column]) {
        grouped[task.column].push(task);
      }
    });
    return grouped;
  }, [tasks, props.columns]);

  const totalTasks = useMemo(() => tasks.length, [tasks]);
  const completedTasks = useMemo(
    () => tasks.filter((t) => t.column === 'done').length,
    [tasks]
  );

  // Handlers
  const handleMoveTask = useCallback(
    (taskId: string, newColumn: string) => {
      setTasks((prev) =>
        prev.map((t) =>
          t.id === taskId ? { ...t, column: newColumn } : t
        )
      );
      taskUpdateAction({ action: 'move', taskId, data: { column: newColumn } });
    },
    [taskUpdateAction]
  );

  const handleEditTask = useCallback(
    (taskId: string, newTitle: string, newPriority?: 'low' | 'medium' | 'high') => {
      if (!taskId) return;
      setTasks((prev) =>
        prev.map((t) =>
          t.id === taskId ? { ...t, title: newTitle, ...(newPriority && { priority: newPriority }) } : t
        )
      );
      setEditingTaskId(null);
      setEditingTitle('');
      const task = tasks.find((t) => t.id === taskId);
      const column = task?.column || 'todo';
      taskUpdateAction({ action: 'edit', taskId, data: { column, title: newTitle, ...(newPriority && { priority: newPriority }) } });
    },
    [taskUpdateAction, tasks]
  );

  const handleAddTask = useCallback(
    (columnId: string) => {
      if (!newTaskTitle.trim()) return;
      const taskId = `task-${Date.now()}`;
      const newTask = {
        id: taskId,
        title: newTaskTitle,
        priority: newTaskPriority,
        column: columnId,
        assignee: '',
        dueDate: '',
      };
      setTasks((prev) => [...prev, newTask]);
      setNewTaskTitle('');
      setNewTaskPriority('medium');
      setAddingColumnId(null);
      taskUpdateAction({ action: 'create', taskId, data: { column: columnId, title: newTaskTitle, priority: newTaskPriority } });
    },
    [newTaskTitle, newTaskPriority, taskUpdateAction]
  );

  const handleStartEdit = useCallback((taskId: string | undefined, currentTitle: string | undefined) => {
    if (taskId && currentTitle !== undefined) {
      setEditingTaskId(taskId);
      setEditingTitle(currentTitle);
    }
  }, []);

  // Actions — fire-and-forget to agent
  const taskUpdateAction = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board
  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={24}>
        {/* SUMMARY BAR */}
        <Stack gap={8}>
          <Heading level={1}>Kanban Board</Heading>
          <Row gap={16} align="center">
            <Badge variant="default" size="lg">
              Total: {totalTasks}
            </Badge>
            <Badge variant="success" size="lg">
              Completed: {completedTasks}
            </Badge>
          </Row>
        </Stack>

        {/* KANBAN COLUMNS */}
        <Row gap={16} align="start">
          {props.columns.map((column) => (
            <div
              key={column.id}
              style={{
                flex: '1 1 320px',
                minWidth: '320px',
                display: 'flex',
                flexDirection: 'column',
              }}
            >
              <Card
                shadow="sm"
                padding={16}
                radius="lg"
                style={{
                  display: 'flex',
                  flexDirection: 'column',
                  height: '100%',
                  minHeight: '500px',
                }}
              >
                {/* Column Header */}
                <Stack gap={12}>
                  <Row justify="between" align="center">
                    <Heading level={3}>{column.name}</Heading>
                    <Badge variant="secondary" size="sm">
                      {(tasksByColumn[column.id] || []).length || 0}
                    </Badge>
                  </Row>
                  <Divider margin={8} />
                </Stack>

                {/* Task Cards */}
                <Stack
                  gap={8}
                  style={{
                    flex: '1 1 auto',
                    overflowY: 'auto',
                    overflowX: 'hidden',
                    paddingRight: 'var(--ggui-spacing-1, 4px)',
                  }}
                >
                  {(tasksByColumn[column.id] || []).map((task) => {
                    if (!task.id || !task.title) return null;
                    return (
                    <Card
                      key={task.id}
                      shadow="sm"
