/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };


// Helper: render star rating
function RatingStars({ rating, count }: { rating: number; count: number }) {
  const fullStars = Math.floor(rating);
  const hasHalf = rating % 1 >= 0.5;
  const emptyStars = 5 - fullStars - (hasHalf ? 1 : 0);
  return (
    <Stack direction="horizontal" gap={4} align="center">
      {Array.from({ length: fullStars }).map((_, i) => (
        <Icon key={`full-${i}`} name="star" size={16} color="var(--ggui-color-warning-500, #f59e0b)" />
      ))}
      {hasHalf && <Icon key="half" name="star" size={16} color="var(--ggui-color-warning-500, #f59e0b)" />}
      {Array.from({ length: emptyStars }).map((_, i) => (
        <Icon key={`empty-${i}`} name="star" size={16} color="var(--ggui-color-outlineVariant, #e4e4e7)" />
      ))}
      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
        {rating.toFixed(1)} ({count || 0})
      </Text>
    </Stack>
  );
}


export default function Component(props: Props) {
  // State
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');


    // Actions — fire-and-forget to agent
  const addToCart = useAction<ActionAddToCartPayload>('addToCart'); // Called when user clicks Add to Cart. Payload: { productId, quantity }
  const addToCart = useAction<ActionAddToCartPayload>('addToCart'); // Called when user clicks Add to Cart. Payload: { productId, quantity }

  // Computed values
  const isOutOfStock = !props.product.stock || props.product.stock <= 0;
  const isLowStock = props.product.stock && props.product.stock > 0 && props.product.stock <= 5;
  const formattedPrice = props.product.price
    ? `${props.product.currency || 'USD'} ${props.product.price.toFixed(2)}`
    : 'N/A';

  // Handlers
  const handleAddToCart = useCallback(() => {
    if (props.product.id && quantity > 0) {
      addToCart({ productId: props.product.id, quantity });
    }
  }, [props.product.id, quantity, addToCart]);

  const handleQuantityChange = useCallback(
    (delta: number) => {
      const maxStock = props.product.stock || 1;
      setQuantity((prev) => Math.max(1, Math.min(prev + delta, maxStock)));
    },
    [props.product.stock]
  );

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={24}>
        {/* TOP SECTION: Image + Details */}
        <Row gap={32} align="start">
          {/* Product Image Placeholder */}
