            borderRadius="var(--ggui-shape-radius-lg, 12px)"
            padding={32}
            style={{ minWidth: '300px', height: '400px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}
          >
            <Stack gap={16} align="center" justify="center">
              <Icon name="image" size={64} color="var(--ggui-color-primary-300, #7dd3fc)" />
              <Text variant="body" color="var(--ggui-color-primary-700, #0369a1)" align="center">
                {props.product.name || 'Product Image'}
