            </Stack>
          </Box>

          {/* Product Details */}
          <Stack gap={16} style={{ flex: 1 }}>
            {/* Title */}
            <Heading level={2}>{props.product.name || 'Product Name'}</Heading>

            {/* Price */}
            <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-primary-600, #0284c7)">
              {formattedPrice}
            </Text>

            {/* Rating */}
            {props.product.rating !== undefined && (
              <RatingStars rating={props.product.rating} count={props.product.reviewCount || 0} />
            )}

            {/* Stock Status */}
            {isOutOfStock ? (
              <Badge variant="error" size="md">
                Out of Stock
              </Badge>
            ) : isLowStock ? (
              <Badge variant="warning" size="md">
                Low Stock ({props.product.stock})
              </Badge>
            ) : (
              <Badge variant="success" size="md">
                In Stock
              </Badge>
            )}
          </Stack>
        </Row>


        {/* MIDDLE SECTION: Tab Navigation */}
        <Tabs
          variant="line"
          size="md"
          activeKey={activeTab}
          onChange={setActiveTab}
          items={[
            {
              key: 'description',
              label: 'Description',
              content: (
                <Stack gap={12} style={{ paddingTop: 'var(--ggui-spacing-4, 16px)' }}>
                  <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
                    {props.product.description || 'No description available.'}
                  </Text>
                </Stack>
              ),
            },
            {
              key: 'specifications',
              label: 'Specifications',
              content: Array.isArray(props.product.specifications) && props.product.specifications.length > 0 ? (
                <Stack gap={12} style={{ paddingTop: 'var(--ggui-spacing-4, 16px)' }}>
                  <Table
                    columns={[
                      { key: 'key', header: 'Specification', width: '40%' },
                      { key: 'value', header: 'Value', width: '60%' },
                    ]}
                    data={
                      (props.product.specifications as Array<{ key?: string; value?: unknown }>).map((spec, idx) => ({
                        key: spec?.key ?? `spec-${idx}`,
                        value: spec?.value ?? 'N/A',
                      })) || []
                    }
                    compact
                  />
                </Stack>
              ) : (
                <Stack gap={12} style={{ paddingTop: 'var(--ggui-spacing-4, 16px)' }}>
                  <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    No specifications available.
                  </Text>
                </Stack>
              ),
            },
            {
              key: 'reviews',
              label: 'Reviews',
              content: Array.isArray(props.product.reviews) && props.product.reviews.length > 0 ? (
                <Stack gap={16} style={{ paddingTop: 'var(--ggui-spacing-4, 16px)' }}>
                  {(props.product.reviews as Array<{ author?: string; rating?: number; text?: string; date?: string }>).map((review, idx) => (
                    <Card key={idx} shadow="none" border={true} padding={16} radius="md">
                      <Stack gap={8}>
                        <Row gap={16} align="center" justify="between">
                          <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                            {review?.author || 'Anonymous'}
                          </Text>
                          {review?.rating !== undefined && (
                            <RatingStars rating={review.rating} count={0} />
                          )}
                        </Row>
                        <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                          {review?.text || 'No review text.'}
                        </Text>
                        {review?.date && (
                          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                            {review.date}
                          </Text>
                        )}
                      </Stack>
                    </Card>
                  ))}
                </Stack>
              ) : (
                <Stack gap={12} style={{ paddingTop: 'var(--ggui-spacing-4, 16px)' }}>
                  <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    No reviews yet.
                  </Text>
                </Stack>
              ),
            },
          ]}
        />


        {/* FOOTER / ACTIONS */}
        {/* BOTTOM SECTION: Quantity Selector + Add to Cart */}
        <Row gap={16} align="center">
          {/* Quantity Selector */}
          <Stack direction="horizontal" gap={8} align="center">
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              Quantity:
            </Text>
            <Button
              variant="outline"
              size="sm"
              onClick={() => handleQuantityChange(-1)}
              disabled={quantity <= 1}
            >
              −
            </Button>
            <Box
              padding={8}
              background="var(--ggui-color-surfaceVariant, #f4f4f5)"
              borderRadius="var(--ggui-shape-radius-md, 8px)"
              style={{ minWidth: '40px', textAlign: 'center' }}
            >
              <Text variant="body" color="var(--ggui-color-onSurface, #18181b)" align="center">
                {quantity}
              </Text>
            </Box>
            <Button
              variant="outline"
              size="sm"
              onClick={() => handleQuantityChange(1)}
              disabled={quantity >= (props.product.stock || 1)}
            >
              +
            </Button>
          </Stack>

          <Spacer size="flex" />

          {/* Add to Cart Button */}
          <Button
            variant="primary"
            size="lg"
            onClick={handleAddToCart}
            disabled={isOutOfStock}
          >
            Add to Cart
          </Button>
        </Row>
      </Stack>
    </Container>
      </Stack>
    </Container>
  );
}

