/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };




export default function Component(props: Props) {
  // Wire hooks — must be called before state/effects that use them
  const sendMessage_action = useAction<ActionSendMessagePayload>('sendMessage');
  const message = useStream<StreamMessage>('message');
  const typing = useStream<StreamTyping>('typing');

  // State for message list and input
  const [messages, setMessages] = useState(props.messages || []);
  const [inputText, setInputText] = useState('');
  const [typingUser, setTypingUser] = useState<string | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const messagesCardRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom when new messages arrive
  const scrollToBottom = useCallback(() => {
    if (messagesCardRef.current) {
      messagesCardRef.current.scrollTop = messagesCardRef.current.scrollHeight;
    }
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  // Handle new messages from stream
  useEffect(() => {
    if (message?.latest) {
      setMessages((prev) => [...prev, message.latest!]);
    }
  }, [message?.latest]);

  // Handle typing indicator
  useEffect(() => {
    if (typing?.latest) {
      if (typing.latest.active) {
        setTypingUser(typing.latest.sender || null);
      } else {
        setTypingUser(null);
      }
    }
  }, [typing?.latest]);

  // Group consecutive messages from the same sender
  const groupedMessages = useMemo(() => {
    const groups: Array<{ sender: string | undefined; messages: typeof messages }> = [];
    let currentGroup: { sender: string | undefined; messages: typeof messages } | null = null;

    for (const msg of messages) {
      if (currentGroup && currentGroup.sender === msg.sender) {
        currentGroup.messages.push(msg);
      } else {
        if (currentGroup) groups.push(currentGroup);
        currentGroup = { sender: msg.sender, messages: [msg] };
      }
    }
    if (currentGroup) groups.push(currentGroup);
    return groups;
  }, [messages]);

  // Send message handler
  const handleSendMessage = useCallback(() => {
    if (inputText.trim()) {
      const payload: ActionSendMessagePayload = {
        text: inputText,
        timestamp: new Date().toISOString(),
      };
      sendMessage_action(payload);
      setInputText('');
    }
  }, [inputText, sendMessage_action]);

  // Handle Enter key in input
  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
      if (e.key === 'Enter' && !e.shiftKey) {
        e.preventDefault();
        handleSendMessage();
      }
    },
    [handleSendMessage]
  );

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={16} style={{ height: '100vh', display: 'flex', flexDirection: 'column' }}>
        {/* HEADER */}
        <Stack gap={8} align="center" justify="between" direction="horizontal">
          <Stack gap={8} align="center" direction="horizontal">
            <Heading level={1}>{props.title}</Heading>
            <Badge variant="primary" size="sm">
              {props.participantCount} participant{props.participantCount !== 1 ? 's' : ''}
            </Badge>
          </Stack>
          {typingUser && (
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {typingUser} is typing...
            </Text>
          )}
        </Stack>

        {/* MESSAGE LIST */}
        {/* MESSAGE LIST */}
        <Card
          ref={messagesCardRef}
          shadow="md"
          padding={16}
          radius="lg"
          style={{
            flex: 1,
            overflowY: 'auto',
            display: 'flex',
            flexDirection: 'column',
            gap: 'var(--ggui-spacing-2, 8px)',
          }}
        >
          {messages?.length === 0 ? (
            <Text
              align="center"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
              style={{ marginTop: 'auto', marginBottom: 'auto' }}
            >
              No messages yet. Start the conversation!
            </Text>
          ) : (
            groupedMessages.map((group, groupIdx) => {
              const isCurrent = group.sender === props.currentUser;
              return (
                <Stack
                  key={groupIdx}
                  gap={4}
                  align={isCurrent ? 'end' : 'start'}
                  style={{ width: '100%' }}
                >
                  {group.messages.map((msg, msgIdx) => (
                    <Box
                      key={`${groupIdx}-${msgIdx}`}
                      paddingX={12}
                      paddingY={8}
                      borderRadius="var(--ggui-shape-radius-lg, 12px)"
                      background={
                        isCurrent
                          ? 'var(--ggui-color-primary-600, #0284c7)'
                          : 'var(--ggui-color-surfaceVariant, #f4f4f5)'
                      }
                      style={{
                        maxWidth: '70%',
                        wordWrap: 'break-word',
                      }}
                    >
                      {msgIdx === 0 && !isCurrent && group.sender && (
                        <Text
                          variant="label"
                          color="var(--ggui-color-onSurfaceVariant, #52525b)"
                          size="xs"
                        >
                          {group.sender}
                        </Text>
                      )}
                      <Text
                        variant="body"
                        color={isCurrent ? '#ffffff' : 'var(--ggui-color-onSurface, #18181b)'}
                      >
                        {msg.text}
                      </Text>
                      {msg.timestamp && (
                        <Text
                          variant="caption"
                          color={isCurrent ? 'rgba(255,255,255,0.7)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}
                          size="xs"
                        >
                          {new Date(msg.timestamp).toLocaleTimeString([], {
                            hour: '2-digit',
                            minute: '2-digit',
                          })}
                        </Text>
                      )}
                    </Box>
                  ))}
                </Stack>
              );
            })
          )}
          <div ref={messagesEndRef} />
        </Card>
        </Card>

        {/* INPUT AREA */}
        <Stack gap={12} direction="horizontal" align="end">
          <TextArea
            label="Message"
            value={inputText}
            onChange={setInputText}
            onKeyDown={handleKeyDown}
            placeholder="Type your message here... (Enter to send, Shift+Enter for newline)"
            rows={2}
            style={{ flex: 1 }}
          />
          <Button
            variant="primary"
            size="md"
            onClick={handleSendMessage}
            disabled={!inputText.trim()}
            leftIcon={<Icon name="send" size={18} />}
          >
            Send
          </Button>
        </Stack>
      </Stack>
    </Container>
  );
}

