// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useStream } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




export default function Component(props: Props) {
  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  // State: merge initial stocks with live updates
  const [stocks, setStocks] = useState(props.stocks || []);
  const [lastUpdated, setLastUpdated] = useState(new Date());
  const [highlightedSymbols, setHighlightedSymbols] = useState<Set<string>>(new Set());

  // Highlight animation: flash for 500ms when price updates
  useEffect(() => {
    if (priceUpdate?.latest?.symbol) {
      const symbol = priceUpdate.latest.symbol;
      setHighlightedSymbols(prev => new Set(prev).add(symbol));
      setLastUpdated(new Date());
      const timer = setTimeout(() => {
        setHighlightedSymbols(prev => {
          const next = new Set(prev);
          next.delete(symbol);
          return next;
        });
      }, 500);
      return () => clearTimeout(timer);
    }
  }, [priceUpdate?.latest?.symbol]);

  // Merge stream updates into stocks array
  useEffect(() => {
    if (priceUpdate?.latest?.symbol) {
      const updated = priceUpdate.latest;
      setStocks(prev =>
        (prev || []).map(stock =>
          stock.symbol === updated.symbol
            ? { ...stock, price: updated.price ?? stock.price, change: updated.change ?? stock.change, changePercent: updated.changePercent ?? stock.changePercent }
            : stock
        )
      );
    }
   }, [priceUpdate?.latest?.symbol, priceUpdate?.latest?.price]);

   // Helper: format price with 2 decimals
   const formatPrice = (price?: number) => {
     return price !== undefined ? `$${price.toFixed(2)}` : '—';
   };

   // Helper: get arrow icon for change direction
   const getArrow = (changePercent?: number) => {
     return changePercent !== undefined && changePercent >= 0 ? '▲' : '▼';
   };

   // Helper: get color based on change direction
   const getChangeColor = (changePercent?: number) => {
     return changePercent !== undefined && changePercent >= 0
       ? 'var(--ggui-color-success-600, #16a34a)'
       : 'var(--ggui-color-error-600, #dc2626)';
   };
  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={16}>
        {/* HEADER */}
        <Stack gap={8}>
          <Stack direction="horizontal" justify="between" align="center">
            <Heading level={1}>Market Watch</Heading>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Last Updated: {lastUpdated.toLocaleTimeString()}
            </Text>
          </Stack>
        </Stack>

        {/* CONTENT */}
        {/* CONTENT */}
        {stocks && stocks.length > 0 ? (
          <CardGrid columns={{ sm: 1, md: 3 }} gap={16}>
            {stocks.map((stock) => {
              const isHighlighted = highlightedSymbols.has(stock.symbol || '');
              const changeColor = getChangeColor(stock.changePercent);
              const arrow = getArrow(stock.changePercent);
              const borderColor = stock.changePercent !== undefined && stock.changePercent >= 0
                ? 'var(--ggui-color-success-200, #bbf7d0)'
                : 'var(--ggui-color-error-200, #fecaca)';

              return (
                <Card
                  key={stock.symbol || `stock-${stocks.indexOf(stock)}`}
                  shadow="md"
                  padding={20}
                  border={true}
                  style={{
                    borderColor: borderColor,
                    transition: 'background-color 300ms ease, box-shadow 300ms ease',
                    backgroundColor: isHighlighted
                      ? 'var(--ggui-color-success-50, #f0fdf4)'
                      : 'var(--ggui-color-surface, #fafafa)',
                  }}>
                  <Stack gap={12}>
                    {/* Ticker Symbol */}
                    <Text size="2xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)" truncate>
                      {stock.symbol || 'N/A'}
                    </Text>

                    {/* Company Name */}
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)" truncate>
                      {stock.name || 'Unknown'}
                    </Text>

                    {/* Divider */}
                    <Divider margin={8} />

                    {/* Price */}
                    <Stack direction="horizontal" justify="between" align="center">
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        Price
                      </Text>
                      <Text size="xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                        {formatPrice(stock.price)}
                      </Text>
                    </Stack>

                    {/* Change Amount */}
                    <Stack direction="horizontal" justify="between" align="center">
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        Change
                      </Text>
                      <Text size="base" weight="medium" color={changeColor}>
                        {stock.change !== undefined ? `${stock.change >= 0 ? '+' : ''}${stock.change.toFixed(2)}` : '—'}
                      </Text>
                    </Stack>

                    {/* Change Percentage with Arrow */}
                    <Stack direction="horizontal" justify="between" align="center">
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        Change %
                      </Text>
                      <Text size="base" weight="medium" color={changeColor}>
                        <span style={{ marginRight: 'var(--ggui-spacing-1, 4px)' }}>{arrow}</span>
                        {stock.changePercent !== undefined ? `${stock.changePercent >= 0 ? '+' : ''}${stock.changePercent.toFixed(2)}%` : '—'}
                      </Text>
                    </Stack>
                  </Stack>
                </Card>
              );
            })}
          </CardGrid>
        ) : (
          <Box padding={40} background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius={8}>
            <Text align="center" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              No stocks to display
            </Text>
          </Box>
        )}

        {/* FOOTER / ACTIONS */}
        <Row gap={8} justify="start">
          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Market Status: {marketStatus.latest?.status ? (marketStatus.latest.status.charAt(0).toUpperCase() + marketStatus.latest.status.slice(1)) : 'Unknown'}
          </Text>
        </Row>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };


// Helper: validate email format
function isValidEmail(email: string): boolean {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
}

export default function Component(props: Props) {
  // State management for all form fields
  const [step, setStep] = useState(1);
  const [name, setName] = useState(props.initialProfile.name || '');
  const [email, setEmail] = useState(props.initialProfile.email || '');
  const [avatar, setAvatar] = useState(props.initialProfile.avatar || props.avatarOptions[0] || '');
  const [role, setRole] = useState(props.initialProfile.role || '');
  const [emailNotifications, setEmailNotifications] = useState(props.initialProfile.emailNotifications ?? true);
  const [theme, setTheme] = useState(props.initialProfile.theme || 'light');

  // Validation states
  const [nameError, setNameError] = useState('');
  const [emailError, setEmailError] = useState('');

  // Validation logic
  const isStep1Valid = useMemo(() => {
    const nameValid = name.trim().length > 0;
    const emailValid = isValidEmail(email);
    return nameValid && emailValid;
  }, [name, email]);

  const isStep2Valid = useMemo(() => {
    return role.length > 0;
  }, [role]);

  // Handler: validate and move to next step
  const handleNext = useCallback(() => {
    if (step === 1) {
      const nameV = name.trim().length === 0;
      const emailV = !isValidEmail(email);
      setNameError(nameV ? 'Name is required' : '');
      setEmailError(emailV ? 'Please enter a valid email' : '');
      if (!nameV && !emailV) {
        setStep(2);
      }
    } else if (step === 2) {
      if (isStep2Valid) {
        setStep(3);
      }
    }
  }, [step, name, email, role, isStep2Valid]);

  // Handler: go back to previous step
  const handleBack = useCallback(() => {
    if (step > 1) {
      setStep(step - 1);
      setNameError('');
      setEmailError('');
    }
  }, [step]);

  // Handler: submit form
  const handleComplete = useCallback(() => {
    complete({
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    });
  }, [name, email, avatar, role, emailNotifications, theme]);

  // Actions
  const complete = useAction<ActionCompletePayload>('complete');

  return (
    <Container maxWidth="lg" padding={24} center>
      <Stack gap={24} align="center">
        {/* STEP INDICATOR */}
          <Stack gap={8} align="center">
          <Heading level={2}>Setup Your Profile</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">Step {step} of 3</Text>
          <Progress value={(step / 3) * 100} max={100} size="md" />
        </Stack>

        {/* STEP 1: PROFILE SETUP */}
        {step === 1 && (
          <Card shadow="md" padding={24} style={{ width: '100%', maxWidth: '500px' }}>
            <Stack gap={16}>
              <Heading level={3}>Profile Setup</Heading>
              <Input
                label="Name"
                value={name}
                onChange={setName}
                placeholder="Enter your full name"
                required
                error={nameError}
              />
              <Input
                label="Email"
                type="email"
                value={email}
                onChange={setEmail}
                placeholder="your@email.com"
                required
                error={emailError}
              />
              <Stack gap={8}>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Avatar</Text>
                  <Stack direction="horizontal" gap={8} wrap>
                  {props.avatarOptions.map((opt) => (
                    <Box
                      key={opt}
                      as={Clickable}
                      onClick={() => setAvatar(opt)}
                      padding={8}
                      borderRadius={8}
                      background={avatar === opt ? 'var(--ggui-color-primary-100, #e0f2fe)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)'}
                      style={{
                        cursor: 'pointer',
                        transition: 'all 200ms ease-in-out',
                        border: avatar === opt ? '2px solid var(--ggui-color-primary-600, #0284c7)' : '2px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                      }}
                    >
                      <Text size="2xl">{opt}</Text>
                    </Box>
                  ))}
                </Stack>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* STEP 2: PREFERENCES */}
        {step === 2 && (
          <Card shadow="md" padding={24} style={{ width: '100%', maxWidth: '500px' }}>
            <Stack gap={16}>
              <Heading level={3}>Preferences</Heading>
              <Select
                label="Role"
                value={role}
                onChange={setRole}
                options={props.roleOptions.map((r) => ({ value: r, label: r }))}
                placeholder="Select your role"
                required
              />
              <Toggle
                label="Email Notifications"
                checked={emailNotifications}
                onChange={setEmailNotifications}
              />
              <RadioGroup
                label="Theme Preference"
                value={theme}
                onChange={setTheme}
                options={[
                  { value: 'light', label: 'Light' },
                  { value: 'dark', label: 'Dark' },
                ]}
                direction="horizontal"
              />
            </Stack>
          </Card>
        )}

        {/* STEP 3: REVIEW & CONFIRM */}
        {step === 3 && (
          <Card shadow="md" padding={24} style={{ width: '100%', maxWidth: '500px' }}>
            <Stack gap={16}>
              <Heading level={3}>Review & Confirm</Heading>
              <Box background="var(--ggui-color-surfaceVariant, #f4f4f5)" padding={16} borderRadius={8}>
                <Stack gap={12}>
                  <Row justify="between" align="center">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Name</Text>
                    <Text>{name}</Text>
                  </Row>
                  <Divider />
                  <Row justify="between" align="center">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Email</Text>
                    <Text>{email}</Text>
                  </Row>
                  <Divider />
                  <Row justify="between" align="center">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Avatar</Text>
                    <Text size="lg">{avatar}</Text>
                  </Row>
                  <Divider />
                  <Row justify="between" align="center">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Role</Text>
                    <Text>{role}</Text>
                  </Row>
                  <Divider />
                  <Row justify="between" align="center">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Notifications</Text>
                     <Badge variant={emailNotifications ? 'success' : 'default'}>{emailNotifications ? 'Enabled' : 'Disabled'}</Badge>
                  </Row>
                  <Divider />
                  <Row justify="between" align="center">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Theme</Text>
                    <Text>{theme === 'light' ? '☀️ Light' : '🌙 Dark'}</Text>
                  </Row>
                </Stack>
              </Box>
            </Stack>
          </Card>
        )}

        {/* NAVIGATION BUTTONS */}
        <Row gap={8} justify="center">
          {step > 1 && (
            <Button variant="ghost" onClick={handleBack}>
              Go Back
            </Button>
          )}
          {step < 3 && (
            <Button
              variant="primary"
              onClick={handleNext}
              disabled={step === 1 ? !isStep1Valid : step === 2 ? !isStep2Valid : false}
            >
              Next
            </Button>
          )}
          {step === 3 && (
            <Button variant="primary" onClick={handleComplete}>
              Complete Setup
            </Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}
